/**
 * Result of analyzing a search query.
 */
export interface QueryAnalysis {
  /** Original query text */
  query: string;
  /** Extracted entities (combined persons, locations, organizations) */
  entities: ExtractedEntity[];
  /** Extracted person names */
  persons: string[];
  /** Extracted location names */
  locations: string[];
  /** Extracted organization names */
  organizations: string[];
  /** Temporal range if detected */
  temporalRange: TemporalRange | null;
  /** Type of question */
  questionType: 'factual' | 'temporal' | 'comparative' | 'aggregation' | 'multi-hop' | 'conceptual';
  /** Query complexity level */
  complexity: 'low' | 'medium' | 'high';
  /** Confidence in the analysis (0-1) */
  confidence: number;
  /** Types of information being requested */
  requiredInfoTypes: string[];
  /** Decomposed sub-queries for multi-hop */
  subQueries?: string[];
}

/**
 * An extracted entity from query analysis.
 */
export interface ExtractedEntity {
  name: string;
  type: 'person' | 'location' | 'organization' | 'unknown';
}

/**
 * Temporal range extracted from query.
 */
export interface TemporalRange {
  start?: string;
  end?: string;
  relative?: string;
}

/**
 * Execution plan for a query.
 */
export interface QueryPlan {
  originalQuery: string;
  subQueries: SubQuery[];
  executionStrategy: 'parallel' | 'sequential' | 'iterative';
  mergeStrategy: 'union' | 'intersection' | 'weighted';
  estimatedComplexity: number;
}

/**
 * A sub-query within a query plan.
 */
export interface SubQuery {
  id: string;
  query: string;
  targetLayer: 'semantic' | 'lexical' | 'symbolic' | 'hybrid';
  priority: number;
  filters?: SymbolicFilters;
  dependsOn?: string[];
}

/**
 * Query Analyzer extracts structured information from queries.
 *
 * Uses rule-based heuristics for reliable extraction of:
 * - Person names
 * - Location names
 * - Organization names
 * - Temporal references
 * - Question type
 * - Query complexity
 *
 * @example
 * ```typescript
 * const analyzer = new QueryAnalyzer();
 * const analysis = analyzer.analyze(
 *   'What projects did Alice work on last month?'
 * );
 * // { query: '...', entities: [...], persons: ['Alice'], temporalRange: { relative: 'last month' }, ... }
 * ```
 */
export class QueryAnalyzer {
  private personIndicators = ['Mr.', 'Mrs.', 'Ms.', 'Dr.', 'Prof.'];
  private temporalKeywords = [
    'yesterday', 'today', 'tomorrow',
    'last week', 'last month', 'last year',
    'this week', 'this month', 'this year',
    'next week', 'next month', 'next year',
  ];
  private questionKeywords = {
    factual: ['what', 'who', 'where', 'which'],
    temporal: ['when', 'how long', 'since', 'until'],
    comparative: ['compare', 'difference', 'vs', 'versus', 'better', 'worse'],
    aggregation: ['how many', 'count', 'total', 'sum', 'average'],
    'multi-hop': ['and then', 'which means', 'therefore', 'related to'],
    conceptual: ['explain', 'why', 'how does', 'what is the meaning', 'understand'],
  };

  /**
   * Analyze a query using rule-based heuristics.
   * Main entry point - returns full QueryAnalysis.
   */
  analyze(query: string): QueryAnalysis {
    const lowerQuery = query.toLowerCase();
    const persons = this.extractPersons(query);
    const locations = this.extractLocations(query);
    const organizations = this.extractOrganizations(query);
    const questionType = this.detectQuestionType(lowerQuery);
    const complexity = this.estimateComplexity(query);

    // Build entities array from extracted names
    const entities: ExtractedEntity[] = [
      ...persons.map(name => ({ name, type: 'person' as const })),
      ...locations.map(name => ({ name, type: 'location' as const })),
      ...organizations.map(name => ({ name, type: 'organization' as const })),
    ];

    // Calculate confidence based on extraction quality
    const confidence = this.calculateConfidence(entities, complexity, questionType);

    return {
      query,
      entities,
      persons,
      locations,
      organizations,
      temporalRange: this.extractTemporalRange(query),
      questionType,
      complexity,
      confidence,
      requiredInfoTypes: this.detectRequiredInfoTypes(lowerQuery),
      subQueries: this.decomposeQuery(query),
    };
  }

  /**
   * Calculate confidence score for the analysis.
   */
  private calculateConfidence(
    entities: ExtractedEntity[],
    complexity: 'low' | 'medium' | 'high',
    questionType: QueryAnalysis['questionType']
  ): number {
    let confidence = 0.5;

    // Higher confidence for simple queries
    if (complexity === 'low') confidence += 0.3;
    else if (complexity === 'medium') confidence += 0.1;

    // Higher confidence when entities are detected
    if (entities.length > 0) confidence += 0.1;

    // Lower confidence for conceptual queries (harder to satisfy)
    if (questionType === 'conceptual') confidence -= 0.2;

    return Math.max(0, Math.min(1, confidence));
  }

/**
 * Extract person names from query.
 */
private extractPersons(query: string): string[] {
  const persons: string[] = [];
  const words = query.split(/\s+/);

  for (let i = 0; i < words.length; i++) {
    const word = words[i];
    // Check for titles followed by names
    if (this.personIndicators.some(ind => word.startsWith(ind))) {
      if (i + 1 < words.length) {
        persons.push(words[i + 1].replace(/[^a-zA-Z]/g, ''));
      }
    }
    // Check for capitalized words that might be names
    if (/^[A-Z][a-z]+$/.test(word) && i > 0 && !/^[A-Z]/.test(words[i-1])) {
      persons.push(word);
    }
  }

  return [...new Set(persons)];
}

/**
 * Extract location names from query.
 */
private extractLocations(query: string): string[] {
  const locationIndicators = ['in', 'at', 'from', 'to', 'near'];
  const locations: string[] = [];
  const words = query.split(/\s+/);

  for (let i = 0; i < words.length; i++) {
    if (locationIndicators.includes(words[i].toLowerCase())) {
      if (i + 1 < words.length && /^[A-Z]/.test(words[i + 1])) {
        locations.push(words[i + 1].replace(/[^a-zA-Z]/g, ''));
      }
    }
  }

  return [...new Set(locations)];
}

/**
 * Extract organization names from query.
 */
private extractOrganizations(query: string): string[] {
  const orgIndicators = ['Inc.', 'Corp.', 'LLC', 'Ltd.', 'Company', 'Co.'];
  const organizations: string[] = [];

  for (const indicator of orgIndicators) {
    const regex = new RegExp(`([A-Z][a-zA-Z]*)\\s*${indicator.replace('.', '\\.')}`, 'g');
    const matches = query.match(regex);
    if (matches) {
      organizations.push(...matches);
    }
  }

  return [...new Set(organizations)];
}

/**
 * Extract temporal range from query.
 */
private extractTemporalRange(query: string): QueryAnalysis['temporalRange'] | undefined {
  const lowerQuery = query.toLowerCase();

  for (const keyword of this.temporalKeywords) {
    if (lowerQuery.includes(keyword)) {
      return { relative: keyword };
    }
  }

  // Check for date patterns
  const datePattern = /\d{4}-\d{2}-\d{2}/g;
  const dates = query.match(datePattern);
  if (dates && dates.length >= 1) {
    return {
      start: dates[0],
      end: dates.length > 1 ? dates[1] : undefined,
    };
  }

  return undefined;
}

  /**
   * Detect the type of question.
   */
  private detectQuestionType(query: string): QueryAnalysis['questionType'] {
    for (const [type, keywords] of Object.entries(this.questionKeywords)) {
      if (keywords.some(kw => query.includes(kw))) {
        return type as QueryAnalysis['questionType'];
      }
    }
    return 'factual';
  }

  /**
   * Estimate query complexity.
   */
  private estimateComplexity(query: string): QueryAnalysis['complexity'] {
    const wordCount = query.split(/\s+/).length;
    const hasConjunctions = /\b(and|or|but|then|therefore)\b/i.test(query);
    const hasMultipleClauses = /[,;]/.test(query);

    if (wordCount > 20 || (hasConjunctions && hasMultipleClauses)) {
      return 'high';
    }
    if (wordCount > 10 || hasConjunctions || hasMultipleClauses) {
      return 'medium';
    }
    return 'low';
  }

  /**
   * Detect what types of information are being requested.
   */
  private detectRequiredInfoTypes(query: string): string[] {
    const infoTypes: string[] = [];

    if (/\b(who|person|people|name)\b/.test(query)) infoTypes.push('person');
    if (/\b(where|location|place|city)\b/.test(query)) infoTypes.push('location');
    if (/\b(when|date|time|year|month)\b/.test(query)) infoTypes.push('temporal');
    if (/\b(how many|count|number|total)\b/.test(query)) infoTypes.push('quantity');
    if (/\b(why|reason|because)\b/.test(query)) infoTypes.push('reason');
    if (/\b(what|which|project|task)\b/.test(query)) infoTypes.push('entity');

    return infoTypes;
  }

  /**
   * Decompose complex queries into sub-queries.
   */
  private decomposeQuery(query: string): string[] | undefined {
    // Split on conjunctions
    const parts = query.split(/\b(and then|and|but|or)\b/i)
      .map(p => p.trim())
      .filter(p => p && !/^(and then|and|but|or)$/i.test(p));

    if (parts.length > 1) {
      return parts;
    }

    return undefined;
  }
}

/**
 * Query Planner generates execution plans from query analysis.
 *
 * Creates optimized plans that:
 * - Select appropriate search layers
 * - Determine execution strategy (parallel/sequential)
 * - Set up query dependencies
 * - Configure merge strategies
 */
export class QueryPlanner {
  /**
   * Create an execution plan from query analysis.
   */
  createPlan(query: string, analysis: QueryAnalysis): QueryPlan {
    const subQueries = this.createSubQueries(query, analysis);
    const executionStrategy = this.selectExecutionStrategy(subQueries);
    const mergeStrategy = this.selectMergeStrategy(analysis);

    return {
      originalQuery: query,
      subQueries,
      executionStrategy,
      mergeStrategy,
      estimatedComplexity: this.calculateComplexity(subQueries),
    };
  }

  private createSubQueries(query: string, analysis: QueryAnalysis): SubQuery[] {
    const subQueries: SubQuery[] = [];
    let id = 0;

    // If query was decomposed, create sub-query for each part
    if (analysis.subQueries && analysis.subQueries.length > 1) {
      for (const sq of analysis.subQueries) {
        subQueries.push({
          id: `sq_${id++}`,
          query: sq,
          targetLayer: this.selectLayer(analysis),
          priority: id === 1 ? 1 : 2,
          dependsOn: id > 1 ? [`sq_${id - 2}`] : undefined,
        });
      }
    } else {
      // Single query
      subQueries.push({
        id: `sq_${id}`,
        query,
        targetLayer: this.selectLayer(analysis),
        priority: 1,
        filters: this.buildFilters(analysis),
      });
    }

    return subQueries;
  }

  private selectLayer(analysis: QueryAnalysis): SubQuery['targetLayer'] {
    // Use symbolic for tag/type/date filtered queries
    if (analysis.temporalRange || analysis.requiredInfoTypes.includes('temporal')) {
      return 'symbolic';
    }
    // Use semantic for complex concept queries
    if (analysis.complexity === 'high' || analysis.questionType === 'comparative') {
      return 'semantic';
    }
    // Use hybrid for balanced approach
    return 'hybrid';
  }

  private selectExecutionStrategy(subQueries: SubQuery[]): QueryPlan['executionStrategy'] {
    const hasDependencies = subQueries.some(sq => sq.dependsOn && sq.dependsOn.length > 0);
    if (hasDependencies) return 'sequential';
    if (subQueries.length > 1) return 'parallel';
    return 'iterative';
  }

  private selectMergeStrategy(analysis: QueryAnalysis): QueryPlan['mergeStrategy'] {
    switch (analysis.questionType) {
      case 'aggregation': return 'union';
      case 'comparative': return 'intersection';
      default: return 'weighted';
    }
  }

  private buildFilters(analysis: QueryAnalysis): SymbolicFilters | undefined {
    const filters: SymbolicFilters = {};
    let hasFilters = false;

    if (analysis.temporalRange) {
      filters.dateRange = {
        start: analysis.temporalRange.start || '',
        end: analysis.temporalRange.end || '',
      };
      hasFilters = true;
    }

    return hasFilters ? filters : undefined;
  }

  private calculateComplexity(subQueries: SubQuery[]): number {
    let complexity = subQueries.length;
    for (const sq of subQueries) {
      if (sq.dependsOn) complexity += sq.dependsOn.length * 0.5;
      if (sq.filters) complexity += 0.5;
    }
    return Math.min(complexity, 10);
  }
}

{
  name: 'analyze_query',
  description: 'Analyze a search query to extract entities, temporal references, question type, and complexity. Useful for understanding query structure before searching.',
  inputSchema: {
    type: 'object',
    properties: {
      query: {
        type: 'string',
        description: 'The query to analyze',
      },
      includePlan: {
        type: 'boolean',
        default: false,
        description: 'Include execution plan in response',
      },
    },
    required: ['query'],
  },
},

case 'analyze_query': {
  const { query, includePlan = false } = args;

  const analyzer = new QueryAnalyzer();
  const analysis = analyzer.analyzeBasic(query);

  let plan = undefined;
  if (includePlan) {
    const planner = new QueryPlanner();
    plan = planner.createPlan(query, analysis);
  }

  return {
    content: [{
      type: 'text',
      text: JSON.stringify({
        query,
        analysis,
        plan,
      }, null, 2),
    }],
  };
}

import { describe, it, expect, beforeEach } from 'vitest';
import { QueryAnalyzer } from '../../../src/search/QueryAnalyzer.js';
import { QueryPlanner } from '../../../src/search/QueryPlanner.js';

describe('QueryAnalyzer', () => {
  let analyzer: QueryAnalyzer;

  beforeEach(() => {
    analyzer = new QueryAnalyzer();
  });

  describe('person extraction', () => {
    it('should extract names after titles', () => {
      const result = analyzer.analyzeBasic('Talk to Dr. Smith about the project');
      expect(result.persons).toContain('Smith');
    });
  });

  describe('temporal parsing', () => {
    it('should detect relative dates', () => {
      const result = analyzer.analyzeBasic('What happened last month?');
      expect(result.temporalRange?.relative).toBe('last month');
    });
  });

  describe('question type', () => {
    it('should detect factual questions', () => {
      const result = analyzer.analyzeBasic('What is the project status?');
      expect(result.questionType).toBe('factual');
    });

    it('should detect comparative questions', () => {
      const result = analyzer.analyzeBasic('Compare Alice and Bob performance');
      expect(result.questionType).toBe('comparative');
    });
  });

  describe('complexity', () => {
    it('should estimate low complexity for simple queries', () => {
      const result = analyzer.analyzeBasic('Find Alice');
      expect(result.complexity).toBe('low');
    });

    it('should estimate high complexity for complex queries', () => {
      const result = analyzer.analyzeBasic(
        'What projects did Alice work on last year, and how do they compare to Bob\'s projects in terms of success?'
      );
      expect(result.complexity).toBe('high');
    });
  });
});

describe('QueryPlanner', () => {
  let analyzer: QueryAnalyzer;
  let planner: QueryPlanner;

  beforeEach(() => {
    analyzer = new QueryAnalyzer();
    planner = new QueryPlanner();
  });

  it('should create plan from analysis', () => {
    const analysis = analyzer.analyzeBasic('Find projects by Alice');
    const plan = planner.createPlan('Find projects by Alice', analysis);

    expect(plan.originalQuery).toBe('Find projects by Alice');
    expect(plan.subQueries.length).toBeGreaterThan(0);
    expect(plan.executionStrategy).toBeDefined();
    expect(plan.mergeStrategy).toBeDefined();
  });
});
